Projection.ArtifactTemplate:
{% for e in evidence %}- evidenceUri: {{ e.evidenceUri }} artifact memory
  uri: {{ e.slots.artifactUri }}
  status: {{ e.slots.status }}
  availableRefs: {{ e.slots.availableRefCount }}
  loadedRefs: {{ e.slots.memoryCount }}
  unavailableRefs: {{ e.slots.unavailableRefCount }}
  oversizedRefs: {{ e.slots.oversizedRefCount }}
  failedRefs: {{ e.slots.failedRefCount }}
  message: {{ e.slots.message }}
{% endfor %}

Summary.ArtifactTemplate:
{% for artifact in result.artifacts.item %}- sourceArtifactUri: {{ artifact.artifactUri }}
  status: {{ artifact.status }}
  loadedRefs: {{ artifact.memoryCount }}
  unavailableRefs: {{ artifact.unavailableRefCount }}
  oversizedRefs: {{ artifact.oversizedRefCount }}
  failedRefs: {{ artifact.failedRefCount }}
{% for read in artifact.refResults.item %}  - ref={{ read.ref }} status={{ read.status }} message={{ read.message }}{% if read.alternativeRef %} alternativeRef={{ read.alternativeRef }}{% endif %}
{% endfor %}{% for memory in artifact.memories.item %}
## {{ memory.ref }} bytes={{ memory.range.startByte }}..{{ memory.range.endByte }}/{{ memory.range.totalBytes }} complete={{ memory.range.complete }}{% if memory.range.nextStartByte %} nextStartByte={{ memory.range.nextStartByte }}{% endif %}
{{ memory.content }}
{% endfor %}{% endfor %}
